+fn ext4_appears_clean_state(state: u16) -> bool {
+    const EXT4_VALID_FS: u16 = 0x0001;
+    const EXT4_ERROR_FS: u16 = 0x0002;
+    const EXT4_ORPHAN_FS: u16 = 0x0004;
+
+    (state & EXT4_VALID_FS) != 0
+        && (state & EXT4_ERROR_FS) == 0
+        && (state & EXT4_ORPHAN_FS) == 0
+}
